// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; dueDate?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed
const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

const getPriorityVariant = (priority?: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' => {
  if (priority === 'high') return 'error';
  if (priority === 'medium') return 'warning';
  return 'success';
};

const getNextColumn = (columns: Array<{ id?: string; name?: string }>, currentColumn?: string): string => {
  const normalized = columns.filter((c) => !!c.id);
  if (normalized.length === 0) return 'todo';
  const idx = normalized.findIndex((c) => c.id === currentColumn);
  if (idx === -1) return normalized[0].id || 'todo';
  return normalized[(idx + 1) % normalized.length].id || 'todo';
};

const createTaskId = (): string => `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [tasksState, setTasksState] = useState<Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>>(props.tasks || []);
  const [newTaskByColumn, setNewTaskByColumn] = useState<Record<string, { open: boolean; title: string; priority: 'low' | 'medium' | 'high' }>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');

  useEffect(() => {
    setTasksState(props.tasks || []);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest || !taskChanged.latest.task) return;
    const incoming = taskChanged.latest.task;
    const action = taskChanged.latest.action;
    setTasksState((prev) => {
      if (action === 'delete' && incoming.id) {
        return prev.filter((t) => t.id !== incoming.id);
      }
      if (!incoming.id) return prev;
      const exists = prev.some((t) => t.id === incoming.id);
      if (!exists) return [...prev, incoming];
      return prev.map((t) => (t.id === incoming.id ? { ...t, ...incoming } : t));
    });
  }, [taskChanged.latest]);

  const tasksByColumn = useMemo(() => {
    const result: Record<string, Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>> = {};
    (props.columns || []).forEach((col) => {
      if (col.id) result[col.id] = [];
    });
    (tasksState || []).forEach((task) => {
      const key = task.column || (props.columns && props.columns[0] && props.columns[0].id) || 'todo';
      if (!result[key]) result[key] = [];
      result[key].push(task);
    });
    return result;
  }, [tasksState, props.columns]);

  const totalCount = (tasksState || []).length;
  const doneColumn = (props.columns || []).find((col) => (col.name || '').toLowerCase() === 'done' || col.id === 'done')?.id || 'done';
  const completedCount = (tasksState || []).filter((task) => task.column === doneColumn).length;

  const ensureAddState = useCallback((columnId: string) => {
    setNewTaskByColumn((prev) => {
      if (prev[columnId]) return prev;
      return { ...prev, [columnId]: { open: false, title: '', priority: 'medium' } };
    });
  }, []);

  const moveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: newColumn } : task)));
      taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    },
    [taskUpdate]
  );

  const saveTaskTitle = useCallback(
    (taskId: string) => {
      const trimmed = editingTitle.trim();
      if (!trimmed) return;
      const updatedTask = { ...(tasksState || []).find((t) => t.id === taskId), title: trimmed };
      setTasksState((prev) => prev.map((task) => (task.id === taskId ? { ...task, title: trimmed } : task)));
      taskUpdate({
        action: 'edit',
        taskId,
        data: {
          column: updatedTask.column || 'todo',
          title: updatedTask.title || '',
          priority: updatedTask.priority || 'medium',
          assignee: updatedTask.assignee || '',
          dueDate: updatedTask.dueDate || '',
        },
      });
      setEditingTaskId('');
      setEditingTitle('');
    },
    [editingTitle, taskUpdate, tasksState]
  );

  const createTask = useCallback(
    (columnId: string) => {
      const localState = newTaskByColumn[columnId] || { open: false, title: '', priority: 'medium' as const };
      const trimmed = localState.title.trim();
      if (!trimmed) return;
      const taskId = createTaskId();
      const todoColumn = (props.columns && props.columns[0] && props.columns[0].id) || 'todo';
      const newTask = { id: taskId, title: trimmed, priority: localState.priority, assignee: '', column: todoColumn, dueDate: '' };
      setTasksState((prev) => [...prev, newTask]);
      taskUpdate({
        action: 'create',
        taskId,
        data: {
          column: todoColumn,
          title: newTask.title || '',
          priority: newTask.priority || 'medium',
          assignee: newTask.assignee || '',
          dueDate: newTask.dueDate || '',
        },
      });
      setNewTaskByColumn((prev) => ({ ...prev, [columnId]: { open: false, title: '', priority: 'medium' } }));
    },
    [newTaskByColumn, props.columns, taskUpdate]
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center">
            <Heading level={3}>Team Kanban Board</Heading>
            <Row gap="var(--ggui-spacing-3)" align="center">
              <Badge variant="primary">Total: {totalCount}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
        </Card>

        {props.columns.length === 0 ? (
          <Alert variant="warning" title="No columns configured">
            Add columns in props.columns to render the board.
          </Alert>
        ) : (
          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
            {(props.columns || []).map((column) => {
              const columnId = column.id || 'unknown';
              const columnTasks = tasksByColumn[columnId] || [];
              const formState = newTaskByColumn[columnId] || { open: false, title: '', priority: 'medium' as const };
              return (
                <Card key={columnId} padding="var(--ggui-spacing-4)" shadow="sm" border radius="lg">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" align="center">
                      <Heading level={4}>{column.name || columnId}</Heading>
                      <Badge variant="default">{columnTasks.length}</Badge>
                    </Row>

                    <Stack gap="var(--ggui-spacing-3)">
                      {columnTasks.length === 0 ? (
                        <Box
                          padding="var(--ggui-spacing-3)"
                          background="var(--ggui-color-surfaceVariant)"
                          borderRadius="var(--ggui-shape-radius-md)"
                        >
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            No tasks in this column.
                          </Text>
                        </Box>
                      ) : (
                        columnTasks.map((task) => {
                          const taskId = task.id || '';
                          const isEditing = editingTaskId === taskId;
                          const nextColumn = getNextColumn(props.columns, task.column);
                          return (
                            <Card key={taskId || `${columnId}-${task.title}`} padding="var(--ggui-spacing-3)" border shadow="none">
                              <Stack gap="var(--ggui-spacing-2)">
                                <Row justify="between" align="center">
                                  {isEditing ? (
                                    <Input
                                      label="Edit task title"
                                      value={editingTitle}
                                      onChange={setEditingTitle}
                                      placeholder="Task title"
                                    />
                                  ) : (
                                    <Text
                                      as={Clickable}
                                      onDoubleClick={() => {
                                        setEditingTaskId(taskId);
                                        setEditingTitle(task.title || '');
                                      }}
                                      variant="label"
                                      color="var(--ggui-color-onSurface)"
                                    >
                                      {task.title || 'Untitled task'}
                                    </Text>
                                  )}
                                  <Badge variant={getPriorityVariant(task.priority)}>{task.priority || 'low'}</Badge>
                                </Row>

                                <Row gap="var(--ggui-spacing-2)" align="center">
                                  <Avatar name={task.assignee || 'Unassigned'} size="sm" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    {task.assignee || 'Unassigned'}
                                  </Text>
                                  <Spacer size="flex" />
                                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                    {task.dueDate ? `Due: ${task.dueDate}` : 'No due date'}
                                  </Text>
                                </Row>

                                <Row gap="var(--ggui-spacing-2)" wrap>
                                  {isEditing ? (
                                    <>
                                      <Button size="sm" variant="primary" onClick={() => saveTaskTitle(taskId)}>
                                        Save
                                      </Button>
                                      <Button
                                        size="sm"
                                        variant="ghost"
                                        onClick={() => {
                                          setEditingTaskId('');
                                          setEditingTitle('');
                                        }}
                                      >
                                        Cancel
                                      </Button>
                                    </>
                                  ) : (
                                    <Button
                                      size="sm"
                                      variant="outline"
                                      onClick={() => {
                                        setEditingTaskId(taskId);
                                        setEditingTitle(task.title || '');
                                      }}
                                    >
                                      Edit
                                    </Button>
                                  )}
                                  <Select
                                    label="Move task"
                                    value={task.column || ''}
                                    onChange={(value) => moveTask(taskId, value)}
                                    options={(props.columns || [])
                                      .filter((c) => !!c.id)
                                      .map((c) => ({ value: c.id || '', label: c.name || c.id || '' }))}
                                  />
                                  <Button size="sm" variant="secondary" onClick={() => moveTask(taskId, nextColumn)}>
                                    Move Next
                                  </Button>
                                </Row>
                              </Stack>
                            </Card>
                          );
                        })
                      )}
                    </Stack>

                    <Divider margin="var(--ggui-spacing-2)" />

                    {formState.open ? (
                      <Card padding="var(--ggui-spacing-3)" border shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
                            value={formState.title}
                            onChange={(value) => {
                              ensureAddState(columnId);
                              setNewTaskByColumn((prev) => ({
                                ...prev,
                                [columnId]: { ...((prev[columnId] || { open: true, title: '', priority: 'medium' }) as { open: boolean; title: string; priority: 'low' | 'medium' | 'high' }), title: value, open: true },
                              }));
                            }}
                            placeholder="Enter task title"
                          />
                          <Select
                            label="Priority"
                            value={formState.priority}
                            onChange={(value) => {
                              const p = (value as 'low' | 'medium' | 'high') || 'medium';
                              setNewTaskByColumn((prev) => ({
                                ...prev,
                                [columnId]: { ...((prev[columnId] || { open: true, title: '', priority: 'medium' }) as { open: boolean; title: string; priority: 'low' | 'medium' | 'high' }), priority: p, open: true },
                              }));
                            }}
                            options={PRIORITY_OPTIONS}
                          />
                          <Row gap="var(--ggui-spacing-2)">
                            <Button variant="primary" size="sm" onClick={() => createTask(columnId)}>
                              Create Task
                            </Button>
                            <Button
                              variant="ghost"
                              size="sm"
                              onClick={() =>
                                setNewTaskByColumn((prev) => ({
                                  ...prev,
                                  [columnId]: { open: false, title: '', priority: 'medium' },
                                }))
                              }
                            >
                              Cancel
                            </Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Box
                        as={Clickable}
                        onClick={() => {
                          ensureAddState(columnId);
                          setNewTaskByColumn((prev) => ({
                            ...prev,
                            [columnId]: { ...(prev[columnId] || { open: false, title: '', priority: 'medium' }), open: true },
                          }));
                        }}
                        padding="var(--ggui-spacing-2)"
                        background="var(--ggui-color-primary-50)"
                        borderRadius="var(--ggui-shape-radius-md)"
                      >
                        <Text variant="label" color="var(--ggui-color-primary-700)">
                          + Add Task
                        </Text>
                      </Box>
                    )}
                  </Stack>
                </Card>
              );
            })}
          </Stack>
        )}
      </Stack>
    </Container>

  );
}
